var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 뒤","JPN":"一週間後","ENG":"One week later","TWN":"一週以後","SCN":"一周以后","DEU":"One week later","FRA":"One week later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이게 차원함선이라는 건가……? 엄청나잖아……?","JPN":"これが次元艦船ってやつか……？　すごいな……","ENG":"This is a dimensional ship...? It's huge...!","TWN":"這就是次元艦船嗎……？太大了吧……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭘 그렇게 하나하나 놀라고 있습니까요?","JPN":"いちいち驚きすぎでやんす。","ENG":"What are you so surprised about?","TWN":"這有什麼好驚訝的？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국 본부에는 이런 함선들이 적어도 수십 대는 더 있습니다요.","JPN":"管理局の本部にはこういう艦船が数十隻はあるでやんす。","ENG":"There are at least dozens of ships like this at the Administration HQ.","TWN":"管理局總部至少有數十艘這樣的艦船。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"수십 대라고……?","JPN":"数十隻も……？","ENG":"Dozens...?","TWN":"數十艘……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 에잉…… 쯧쯧!","JPN":"それと……ちっちっち！","ENG":"And– Ugh, tsk tsk.","TWN":"還有……嘖嘖！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"함선 탈때는 신발 벗고 타야 하는 것도 모릅니까요?","JPN":"艦船に乗る時は靴を脱ぐのが常識でやんすよ！","ENG":"Don't you know you have to take off your shoes when you get on the ship?","TWN":"你不知道艦船內必須脫鞋嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아주 매너 점수가 빵점입니다요!","JPN":"まったくマナーがなってない人でやんす！","ENG":"You're so uncivilized!","TWN":"你真是一點禮貌都沒有！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그, 그런 거였어!?","JPN":"そ、そうだったのか！？","ENG":"R-really?!","TWN":"是、是嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐야! 다들 신고 있잖아, 죽을래?","JPN":"何だよ、みんな靴履いてるじゃないか！　嘘ついたな！","ENG":"Hey! Everyone else is wearing their shoes! You...!","TWN":"什麼啊！大家都穿著的啊，你想死嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"킥킥, 속았습니다요~ 바보입니다요~ 아주 시골 고양이입니다요~","JPN":"ききき、騙されたでやんす～　バカでやんす～　田舎くさい猫でやんす～","ENG":"Keke! Fooled you! You're so gullible! Looks like you're a hillbilly cat!","TWN":"嘻嘻，上當了吧～笨蛋～沒見識的小貓咪～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우갹!!","JPN":"うぎゃあ！！","ENG":"Eep!!","TWN":"呃啊！！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그나저나 우리 전대원들 말고 관리국 지원병력도 많이 있잖아?","JPN":"それにしても、うちの戦隊員の他にも管理局の支援兵力がけっこうついて来るんだな。","ENG":"By the way, I see a lot of support troops from the Administration besides our division here.","TWN":"話說回來，除了我們戰隊員之外，管理局還有很多的支援部隊吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우으…… 그야 당연한 거 아닙니까요.","JPN":"うう……そんなの当たり前でやんす。","ENG":"Ooh... Of course, you do.","TWN":"呃……那當然。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아무리 소규모 작전이라고 해도 이면세계에서는 어떤 일이 벌어질지 모르는 겁니다요.","JPN":"いくら小規模の作戦とはいえ、裏世界では何が起きるかわからないでやんすから。","ENG":"Even if it's a small-scale operation, nobody knows what will happen in the Counterside.","TWN":"誰也不知道在異界裡會發生什麼，無論是多麼微小的作戰。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"카운터와 지원병력이 합을 맞추는 건 기본입니다요.","JPN":"カウンターと支援兵力が力を合わせるのは当然でやんす。","ENG":"Everyone knows Counters and troops have to work together.","TWN":"制裁者和支援部隊相互配合才是最基本的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"게다가 전대장님도 안 계신 상황이니…….","JPN":"それに、戦隊長も不在だから……","ENG":"And because Commander isn't here...","TWN":"而且，戰隊長也不在……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러고 보니, 그…… 라이오넬 전대장이라고 했나? 그 사람은 어디 있는 거야?","JPN":"そういえば、その……ライオネル戦隊長だっけ？　その人はどこにいるんだ？","ENG":"Oh, now that you mention it... Commander Lionel, was it? Where is he, anyway?","TWN":"現在我想起來了，你是說……萊諾戰隊長嗎？他人到底在哪裡？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"부재중이라는 이야기를 듣긴 했는데 여태 한 번을 못 봤네?","JPN":"しばらく留守にしてるとは聞いたけど、なかなか帰って来ないんだな。","ENG":"I heard he's away, but I've never seen him once.","TWN":"聽說他不在隊裡，我到現在還一次沒見過他呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"헤엥? 아직 그런 것도 모르고 있었습니까요?","JPN":"ええ？　まだ知らないでやんすか？","ENG":"Huh? You still don't know?","TWN":"欸？你還不知道嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그야 아무도 가르쳐 준 적이 없으니까. 꼭 알아야 하는 거야?","JPN":"そりゃあ、誰も教えてくれなかったからな。知る必要ってあるのか？","ENG":"Yeah, because no one ever told me. Do I have to know?","TWN":"從前又沒有人告訴過我……難道我一定要知道這些嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히이…….","JPN":"キヒイ……","ENG":"Hngh...","TWN":"吱……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 작전 시작에 앞서 마지막으로 브리핑하겠습니다.","JPN":"では、作戦を開始する前に、最後のブリーフィングを行います。","ENG":"Then, let's do one last briefing before starting the operation.","TWN":"現在，開始作戰之前的最後一次簡報。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};